import re

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    if subdomain_prefix and re.fullmatch(r'[a-zA-Z0-9.-]+', subdomain_prefix):
        if not subdomain_prefix.startswith(('.', '-')) and not subdomain_prefix.endswith(('.', '-')) and '..' not in subdomain_prefix:
            return f"https://{subdomain_prefix}.{domain}"
    return f"https://{domain}"

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not user_id:
        return None
    # Prevent path traversal and query injection (CWE-22, CWE-601)
    if any(c in user_id for c in ('/', '?', '#', '\\')):
        return None
    return f"{api_url.rstrip('/')}/{user_id}"

